import SwiftUI
import Charts

struct DailyData: Identifiable {
    let id = UUID()
    let day: String
    let income: Double
    let spending: Double
}

struct BarChartView: View {
    let data: [DailyData]

    var body: some View {
        Chart(data) { item in
            BarMark(
                x: .value("Day", item.day),
                y: .value("Income", item.income)
            )
            .foregroundStyle(.green)

            BarMark(
                x: .value("Day", item.day),
                y: .value("Spending", item.spending)
            )
            .foregroundStyle(.red)
        }
        .frame(height: 250)
    }
}

struct LineChartView: View {
    let data: [DailyData]

    var body: some View {
        Chart(data) { item in
            LineMark(
                x: .value("Day", item.day),
                y: .value("Income", item.income)
            )
            .foregroundStyle(.blue)
            .symbol(.circle)
        }
        .frame(height: 200)
    }
}
